import{_ as e,o as p,c as a,j as r,a as o,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const h=JSON.parse('{"title":"魔族Slayer","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/1.生理类/魔族Slayer.md","filePath":"4.资源分区/1.血统与训练/1.生理类/魔族Slayer.md"}'),t={name:"4.资源分区/1.血统与训练/1.生理类/魔族Slayer.md"};function l(s,b,i,d,y,c){return p(),a("div",null,[...b[0]||(b[0]=[r("h1",{id:"魔族slayer",tabindex:"-1"},[o("魔族Slayer "),r("a",{class:"header-anchor",href:"#魔族slayer","aria-label":'Permalink to "魔族Slayer"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌035")])])],-1),n('<h1 id="魔族slayer-1" tabindex="-1">魔族Slayer <a class="header-anchor" href="#魔族slayer-1" aria-label="Permalink to &quot;魔族Slayer&quot;">​</a></h1><p>魔族Slayer<br> 描述：魔族Slayer与忍者Slayer有许多相同之处，但归根结底、魔族Slayer的体内既没有奈落ナラク，也没有藤木户健二的才能。就连忍者装束都不是用在血液中包含空手道元素的血液编织而成，而是五车制的 “cosplay ”而已。<br> 于是答案显而易见，魔族Slayer不是忍者，而是对魔忍不脱裤子系，对魔忍与忍者的区别就像是上方落语和江户落语的区别一样。</p><p>D级<br> D+600<br> 【对魔粒子】：“所谓对魔粒子就是恶魔与对魔忍们使用的一种特殊粒子，是在对魔忍世界观下因魔界与地球连接而广泛存在于世界中、能够引发超自然现象的媒介；对魔忍能够使用对魔粒子，则是因为体内有着魔族血统。”<br> 你开启对魔粒子能量池，这视为魔力的变体，关键属性为耐力，上限是耐力的两倍。对魔粒子的恢复方式是通过长休息完全恢复，或是经过15分钟的坐禅、冥想等行为进行一次关键属性检定，恢复成功数两倍的对魔粒子，每日恢复最大不超过上限的3倍。</p><p>对魔粒子的基础用法：<br> 1.支付1点对魔粒子，你在生理相关检定上获得1DP增强加值，持续一场景。<br> 2.支付1点对魔粒子，你获得1点洞察防御，持续一场景。</p><p>【忍者装束】：消费一个自由动作，你可以运用速装术，为自己换上一套赤黑色的“忍者”装束，持续时间无限/或至自由动作解除；由于装束具有着轻量化改造过的防弹背心，视为具有基于基础防御的【防弹】。</p><p>你的天生武器视为具有3L伤害，伤害类型：物理-钝击。</p><p>附：左前的上衣，让人领悟到既是常时战斗装束的同时，又是死亡装束；下半身是大腿到小腿都膨胀起来的异样裙裤，脚上穿着暗色的地下足袋；缠着头巾的头部被面甲覆盖，令人无法看清全貌；在那仿佛红色线香的不祥色调的瞳孔下方，覆盖了鼻子到下颚部位的那个面甲，用绝断的笔法刻上了“魔杀”二字。</p><p>C级<br> C+1200<br> 【Lesser】：“虽然被称为最强的存在有很多，但无敌和不死之身并不存在。即使是乍看之下不讲理且无法抵抗的忍术，也一定有其弱点；直到最后，能派上用场的是忍者的五体。”</p><p>你在生理相关检定上获得1DP修行加值与1个额外附加成功数；你在使用对魔粒子基础用法时，无需消费对魔粒子。</p><p>【火遁术】：“这就是魔族Slayer的秘中之秘，在家族传承的异能系忍术，火遁术之中，也是格外异类的一种，能够召唤人间地狱之炎。然而其威力过于不可控，以至于能发挥的效果很少。”<br> 消费一个自由动作并支付6点对魔粒子能量，你在该场景内攻击可以转为火焰能量伤害，同时附带1点不可豁免的燃烧不良点数，这一燃烧不良点数的来源为命运而非环境。<br> 【火遁术与相关能力需要你一次性支付3XP进行训练后才能使用。】</p><p>B级<br> B+2400<br> 【Greater】：“即使术被封印，即使被多数人包围，即使被卑鄙的手段ambush偷袭，最后能派上用场的还是空手道，只会依赖术的三下很快就会死去。No空手道No忍者。”<br> 你在生理相关检定上再获得7DP修行加值与1个额外附加成功数。</p><p>【火遁术？】：全称“阿鼻Inferno狱火地狱术”，一旦与这种火焰所接触，就会造成致命伤，地狱业火几乎无法被扑灭，也无法治愈带来的伤害。而且不分物体或是并非物质之物，甚至能够燃烧概念、忍术、灵魂等事物。<br> 消费一个移动动作并支付10点对魔粒子能量，你在该场景内攻击具有【法破】特性，伤害类型可以转为火焰能量，在C级的基础上额外附带1点不可豁免的燃烧不良点数，与【B级重伤】效果，这一燃烧不良点数的来源为命运而非环境。<br> 【仅限对魔忍世界观下，你在启动火遁术？后，无视任何由对魔粒子所推动的效果；此外，无论是否启动，你免疫不超过B级附身来源的效果影响，这个效果并没有需要处于对魔忍世界观的限制。】</p><p>研发（C+1000）：你免疫不超过B级诅咒/祝福来源的效果；启动【火遁术？】后，你的攻击所击杀的目标，若具的复活类效果在A级及以下将无法复活。</p><p>A级<br> 前置：茶道宗师<br> A+4800<br> 【Arch】：“Lesser、Greater、Arch，这些充其量只是忍魂级别的划分，并不能作为真正的评判标准；但作为空手道而言，你已经抵达了开祖级的水准，足以被称之为Arch。”</p><p>从现在开始，你可以使用一个移动动作将体内的对魔粒子最大限度活性化，效果持续时间为一场景；持续期间内，你可以将力量或敏捷计入你的攻击检定（取决于你的攻击主属性是力量还是敏捷，力量就可以加入敏捷，敏捷就可以加入力量），你的攻击检定的出目增加一半，每轮只能因此增加一次出目。<br> 你还会获得等同自身【耐力】一半的防御附加成功，基于洞察防御。</p><p>【魂之牢狱】：自从魔界与地球连接之后，魔族的暴虐、他们带来的科技，以及利用科技舍弃人心之人的残虐，都宛如恶魔一般无情地膨胀了起来。光是Hell一词已经不足以形容。对作为魔忍奔赴前线的魔族Slayer来说，憎恨魔族的根基早已在这世上扎根。<br> 『魔族，杀无赦！』于是，阿鼻Inferno地狱术，八大地狱中背负最重罪责的亡者所坠落的地狱之炎，酿造出了魔族Slayer体内不存在的奈落，那赤黑之炎正是阿鼻Inferno地狱术的火焰，是由他的术所创造出来的魂之监狱！</p><p>你需要在购买B级魔族Slayer研发（非下属能力）后才能使用这一能力；你的【火遁术？】正式更名为【阿鼻Inferno狱火地狱术】，相关能力词缀一律变更为后者；【阿鼻Inferno狱火地狱术】只需要自由动作即可启动，对魔粒子的消耗提升至14，造成的重伤等级提升至A级，禁止复活等级与相关影响等级提升至S级，攻击可以自由留手（用于折磨人）。</p><p>【魔族Slayer下属技艺】<br> 空手道训练<br> 价格：见下<br> 描述：“你那与其说是空手道，不如说是将骨法或者日本拳法，还有摔跤技和卡波耶拉（Capoeira）混在一起……”<br> 效果：<br> 你接受了正规的空手道训练，这使你在进行攻击或防御性动作时可以宣言特定的空手道招式，这些空手道招式皆正常视为攻击技、移动技、防御技等内容，作为主动使用的招式处理。</p><p>支付D+500：习得【Chop手刀】【Chop突刺】。</p><p>支付C+1000：习得【风刃空手道】。</p><p>支付D+500：习得【柔术】。</p><p>支付C+1000/B+2000：习得【大受身】C或B级，需独立购买。</p><p>支付C+2000：习得【Meia Lua de Compasso(半月圆规踢)】。</p><p>支付B+2000+3XP：习得【杀伐空手道】。</p><p>支付B+3000：习得【舍肉留骨】。</p><p>Chop手刀<br> 动作：标准动作<br> 距离：触及距离<br> 目标：单一目标<br> 持续：立即<br> 消耗：无<br> 效果：你并掌做刀，对触及距离内的单一目标进行一次近战肉搏攻击；本次攻击检定获得2DP技艺加值，附带【破甲4】，伤害类型转为物理-挥砍。</p><p>Chop突刺<br> 动作：标准动作<br> 距离：触及距离<br> 目标：单一目标<br> 持续：立即<br> 消耗：无<br> 效果：若上一轮你使用过Chop手刀，则你消费一个标准动作使用这一能力，将手刀变招为贯手，对触及距离内的单一目标进行一次近战肉搏攻击；本次攻击附带【高速3】，在进行部位攻击时降低2点部位减值，并额外造成1点韧性伤害。</p><p>风刃空手道<br> 分类：被动<br> 描述：“InstructionOne（第一堂课）！钢刃斩得断的东西，风刃没理由斩不断！”<br> 效果：风刃空手道分为下述两种效果，你可以在每轮开始时选择使用哪一种效果。</p><p>【风刃正突】：“利用携裹的狂风化作流体的利刃的技巧，所习得者的攻击距离比看起来的要远的多。”<br> 你在攻击可以宣言这一能力，使本次攻击的触及距离增加等同传奇力量*2米，攻击伤害类型改为物理-挥砍。</p><p>【风刃残心】：“在承受攻击前，利用风压进行回避的技术，某种意义上剑道中的残心类似。”<br> 当你进行基础规则中的招架行为时，你可以宣言这一能力，随后可以在招架的同时进行一次移动，本次移动距离不可超过【25+传奇敏捷*10】米。</p><p>研发（C+1000）：你可以选择在使用【风刃空手道】时，额外支付6点对魔粒子能量。随后在该场景内，宣言【风刃正突】后进行的攻击附带【破甲10】【高速10】。</p><p>柔术<br> 分类：被动<br> 描述：最基本的柔术，保持自身稳固，反制擒抱类行为，同时也对限制敌人行动有着重要的作用。<br> 效果：每轮一次，你在攻击后可以分别追加绊摔与拖拽，目标需要使用正常流程对抗你的那次攻击检定（作为DC），失败则目标陷入伏地状态/被拖拽差值距离，遵循相应的规则。<br> 显然的，是否追加绊摔与拖拽，以及这两种行为的先后顺序由你自行决定。</p><p>大受身<br> 动作：见下<br> 目标：自身<br> 持续：见下<br> 消耗：无<br> 描述：将应该传到身体的冲击全部导向了大地，也可以在高空坠落时变成用指尖、手掌、肘部依次接地，从肩膀到背部，然后依次将身体压在地面上，阶段性地吸收全击！最后通过滚动来卸去所有冲击的力量！<br> 效果<br> 【C级】：你免疫坠落伤害；你获得DR3/音波（基于洞察防御），并且额外获得2点洞察防御。<br> 【B级】：移动动作使用，随后在当轮内你所受到的下一次攻击的伤害减半。</p><p>半月圆规踢<br> 前置：柔术，大受身（C级或以上）<br> 动作：见下<br> 目标：单一目标<br> 持续：立即<br> 描述：以类似Bridge的姿势站了起来，然后维持这个姿势使出踢击！或是以被抓住的身体部位支点，用力踢出的变体型的Meia Lua de Compasso(半月圆规踢)！由于接触地面的部位作为辅助，可以使出数倍威力的强力踢击。<br> 这就是中世纪越过大海传播到南美的暗黑空手道踢技，Meia Lua de Compasso(半月圆规踢)！<br> 效果：你只有在被擒抱或被绊摔（包括其他会使你进入擒抱/伏地状态的效果）时才能使用这一能力。<br> 你需要先使用一个反射动作并透支下一轮的标准动作（如常占用下一轮对应的AP与可转化动作次数），随后立刻获得持续一轮的【免疫擒抱状态】并且从伏地状态起身所需的动作下调1级（自由-花招-迅捷-移动-标准-整轮），随后在移动5+传奇敏捷*5米的同时对那个使你满足使用该能力条件的单位进行一次普通肉搏攻击，无法应用任何招式。<br> 上述行为正常具有【打断性】，并且那次攻击还会额外获得【幻灭】特性。</p><p>杀伐空手道<br> 分类：被动<br> 描述：杀伐空手道即是在无穷尽的习得精进格斗技术而得到的产物，洗练技艺而而形成的力量。<br> 效果：你每习得一项魔族Slayer下属D级能力，就在攻击检定上获得1DP修行加值；你每习得一项魔族Slayer下属C级能力，就在攻击检定上获得1个额外附加成功数，并获得1个基于洞察防御的附加成功数。</p><p>舍肉留骨<br> 分类：被动<br> 描述：“听好了，魔族Slayer。不论敌人能使出多么奇异多么压倒性的招式，只要汝自己的空手道坚不可摧便不足为惧。想胜过敌人的本领，就舍弃汝的肉只留下骨吧，扪心自问，然后chop，专注于chop吧。”<br> 「咿呀—！」好快！　「咕哇—！」不断地chop后不断的继续重复chop的魔族Slayer如今已经与chop的概念同化，变成了chop同样的存在，只是单纯的茶道的炎之轨迹！<br> 效果：<br> 每轮开始时，你额外获得4AP用于施展魔族Slayer的相关能力；你进行的近战肉搏攻击获得【高速10】，在处理目标的防御后若这些高速仍有剩余，则这些剩余高速转化为攻击检定上的技艺加值。</p><p>茶道Meditation<br> 价格：D+1000/C+1500（逐级购买，效果替换）<br> 动作：迅捷动作<br> 消耗：1点意志力/2点意志力<br> 持续：一场景<br> 描述：这是太古暗杀术茶道的极意，茶道呼吸。通过吸入大气中稀薄的对魔粒子，补充在激烈的战斗中枯竭的对魔粒子，以独特的手法使其在体内高速循环，治愈伤口，并代谢着体内的毒素。<br> 效果<br> 【D级】：<br> *你获得快速医疗2（医疗点数24）。<br> *你获得异常点治疗1（医疗点数8），仅针对疲乏不良点数生效。<br> *你免疫D级毒素/药物效果带来的影响。</p><p>【C级】：<br> *你获得快速医疗4（医疗点数48）；你的伤势不会自然恶化。<br> *你获得异常点治疗1（医疗点数8），仅针对疲乏不良点数生效。<br> *你免疫C级毒素/药物效果带来的影响。<br> *每轮开始时，你的对魔粒子能量恢复1点，无法超过每日恢复上限。<br> *你在强韧豁免上获得2DP增强加值。</p><p>茶道宗师<br> 前置：茶道Meditation（C级），茶碗<br> 分类：被动<br> 描述：宗师级的茶道境界。<br> 效果：支付C+1000，你在使用茶道Meditation时无需消费意志力，也无需使用迅捷动作；茶道Meditation提供的毒素/药物免疫能力提升至B级，强韧豁免加值提升至4DP；每轮一次，你在使用对魔粒子能量时，消耗减少等同你的传奇沉着*1点。<br> 【特殊的是，你无条件免疫敏感度3000倍的任何药物、毒素等效果。】</p><p>忍者体质<br> 价格：C+2000/B+3000（逐级购买，效果替换）<br> 分类：被动<br> 描述：你的身体虽然显得比较瘦小，但肌肉束聚集成带状，密度高得惊人，一旦开始战斗，就会因为氧气和抗魔粒子的循环而隆起，臂力足以将钢筋扭断而不是折断，忍者这种生物真是厉害。<br> 效果<br> 【C级】：你在强韧豁免上获得【8加骰】；你在进行近战肉搏时，天生武器伤害提升12L，但无法使用除魔族Slayer下属【双截棍】以外的武器，无论是拳套类还是其他肉搏武器，或者其他能提供武器模板类效果的能力，都无法生效。</p><p>【B级】：你在力量相关检定与强韧豁免上获得【8加骰】；你在进行近战肉搏时，天生武器伤害提升21L，具有2个额外攻击附加成功数，但无法使用除魔族Slayer下属【双截棍】以外的武器，无论是拳套类还是其他肉搏武器，或者其他能提供武器模板类效果的能力，都无法生效。</p><p>强手里剑<br> 价格：C+1500<br> 动作：见下<br> 目标：单一目标<br> 距离：等同投掷距离<br> 消耗：无<br> 描述：全身的肌肉像Rope绳子一样隆起，完全同步从下半身到上半身的肌肉扭转动作，将能够射出一千发手里剑的力量集中在一发手里剑上，与胡乱投掷的快速球是完全不同的境界！<br> 这是将手里剑架在腰间，以注入全身力量的左手拇指和食指将其固定，再用注入了足以使其脱手的力量的右手投掷出去，形成的有如弹额头一般的强手里剑变体！<br> 效果：当你使用迅捷动作为【四方手里剑】增加出手速度时，【四方手里剑】的武器伤害提升至18L，附带【贯穿】【破甲5】，因武器伤害获得的破防能力转为【破甲】。</p><p>连续强手里剑<br> 分类：被动<br> 价格：C+2000<br> 描述：比寻常的忍者臂力和精练的空手道赋予了攻击惊人的韧性，不仅需要相当的力量才能将其接下开，其威力甚至足以让全身感到麻痹。更要命的是，这一招已经可以连续发射！<br> 效果：你需要习得强手里剑后才能购买这一能力；当你获得强手里剑的效果并进行投掷【四方手里剑】的攻击时，你可以对投掷射程一半距离的前方扇形内所有敌对目标进行攻击；【四方手里剑】从短点射上升至连射。<br> 若目标处于格挡或对这次攻击应用了招架，则这次攻击对于那些格挡/招架的目标而言，额外获得1DP技艺加值与1个额外附加成功数，并附带1点不可豁免的肢体妨碍不良点数（全身），这是由于强大的力量均匀的传导在目标全身上下所导致的结果，因此造成的是二档肢体妨碍而非一档。</p><p>业火地狱<br> 前置：魔族Slayer（A级）<br> 价格：A+8000<br> 动作：整轮动作<br> 目标：自身<br> 消耗：14点对魔粒子<br> 持续：一场景<br> 描述：阿鼻Inferno地狱术虽然能烧毁无形之物，但同时也是折磨自己的阿鼻地狱之火！那火焰所焚烧的对象也包括自己！<br> 这是能够烧毁现象，灵魂，无形之物！甚至连因果都能焚烧殆尽的火焰！！如果全力释放恐怕只有五分钟左右的火力，再继续下去的话，即使是耐热的对魔忍装束也会被烧毁，身体，肌肉，骨头都会被烧焦。<br> 阿鼻Inferno地狱术不是像不净之炎那么方便的东西，像是烧灼伤口、消灭体内的毒素，甚至接回断肢的异常再生力，都无法以阿鼻Inferno地狱术重现，这火焰本质上是净化之火。它是为了焚烧和净化罪人的灵魂而存在的，不是为了生者而存在的东西。<br> 效果：你在魔族Slayer中本体或研发获得的附身、诅咒/祝福免疫等级提升至A级，并且免疫不超过A级命运来源效果的影响；你的攻击附带等同伤害出目的燃烧不良点数，正常豁免，来源视为A级命运来源；你在进行近战攻击时，触及距离提升至敏感范围，可以同时攻击触及距离内的所有敌对目标，这是最大火力下阿鼻Inferno地狱术所制造出红莲地狱一般的景象。<br> 此外，你还会获得基于偏斜/力场防御的【反震】与【折射】，前者造成火焰能量伤害，你需要在获得这一能力时选择基于偏斜还是力场防御。</p><p>红色巨猩=San<br> 价格：A+7000<br> 描述：「首先，你必须舍弃不必要的智慧」「哈？」。<br> 说到底在这个世界上多得是世间多的是‘一力降十会’的案例，小手段、卑鄙跟暴力，都是因为无法对抗暴力才准备的，如果用更强大的暴力去击溃对方，一切都会变得毫无意义，既然如此，拥有优秀暴力的人，只要一味地让暴力变得尖锐，就会比半吊子的泛用型还要耀眼。<br> 「我授予你Instruction吧。简单的事情就保持简单比较好。而且任何事情都用暴力解决是最好的。因为最后只要把所有人都杀掉就好。汝有能力做到这一点，只要一直磨炼它就行了」「任何事情都用暴力……最后把所有人都杀掉……」<br> 基本上对魔忍这种工作就是要靠刀剑厮杀，所以最后能够发挥效果的还是个人拥有的暴力，而且，不管先后顺序，只要从能够杀掉的家伙开始杀掉，最后把所有人都杀掉的话，帐尾也会对的。<br> 「听好了，汝舍弃智慧吧。只要大喊一声『斩』然后砍下去，世上大部分的问题都能顺利解决」。<br> 效果：你免疫不超过A级的混乱、胁迫、支配、心灵来源的效果影响，你免疫恐惧或沮丧异常点数带来的减值和严重后果（购买时选择免疫恐惧还是沮丧），这是因为你领悟到了任何事情都用暴力解决而得到的结果；你的攻击命中敌对目标后，目标需要使用意志豁免对抗伤害出目，失败则在该场景内陷入A级创伤来源的【支配】状态，无法攻击你和你所指定的特定人群，因为你的暴力直接在物理和心理上摧毁了目标的防线。</p><p>选开：若ST允许，只要目标陷入过这一支配效果，你就可以酌情获得对目标的一定数值的恐吓检定表现加值（不会超过你的力量数值），这一效果只在非战斗检定的社交活动中生效。</p><p>【魔族Slayer下属装备】<br> 手里剑Holster<br> 价格：D+500<br> 描述：由于对魔忍体内只有对魔粒子，因此无法从血液中的空手道成分中自行生成手里剑，所以对魔忍组织的技术部为魔族Slayer准备了专用的手里剑Holster皮套。<br> 效果：手里剑Holster占据【腰带位】，你可以从中取出【四方手里剑】进行投掷攻击。<br> 【四方手里剑】视为轻投掷武器，武器伤害6L，具有【高速1】【短点射】，体积1，伤害类型：物理-穿刺，正常遵循投掷攻击规则；当你使用迅捷动作增加投掷【四方手里剑】的出手速度时，投掷【四方手里剑】的攻击会额外获得【高速1】【破甲2】。</p><p>【四方手里剑】具有【无限子弹】，这意味着你总是可以从手里剑Holster中取出新的【四方手里剑】；【四方手里剑】作为对魔忍的定制武器，其他单位在使用时只能将其视为0B，不具有任何其他特性的武器，【四方手里剑】在投掷攻击后会自动损坏，无法回收。</p><p>茶碗<br> 价格：D+1000<br> 分类：奇物<br> 描述：达到茶道呼吸之极致的高手，仅凭独特的「嘶——！哈——！」节奏即可运转——但要达到那种境界需要漫长的修习。要一边感受着头顶开启大门的感觉，一边与世界一体化并将对魔粒子引入自己体内，就必须通过茶汤和禅来磨练感觉。<br> 其中最不可或缺的就是自己的茶碗。那是用来面对自我的容器，里面盛满的茶是精神本身的体现。只要稍微乱了阵脚，泡沫就会不均匀——茶的味道也会浑浊，所以茶碗是培养精神均衡的核心。<br> 效果：携带此奇物时，你无法使用占据护符位的奇物，但具有免疫不超过C级混乱/胁迫/支配来源效果影响的能力。<br> 当你使用茶道Meditation时，额外支付1点意志力，可以使茶道Meditation提供的快速医疗增加1点，扩大12点医疗点数，并获得1DP三豁免上的修行加值，持续一场景。<br> ——<br> 获得此奇物后，每经过两场影片，你就会再获得一次该奇物提供的好处（即最多因此获得3点快速医疗，三豁免上的3DP修行加值，扩大36点医疗点数）。</p><p>双截棍<br> 价格：D+1000<br> 分类：短棍<br> 描述：用于施展空手道的必备武器之一，只要自由自在地挥舞着双节棍，就能将四周的事物破坏殆尽。<br> 效果：这是一件双截棍，武器伤害3L，具有【格挡1】，分类为短棍但使用专业为：异种武器-双截棍。<br> 具有【空手道】相关任意能力与异种武器-双截棍专业的单位，在使用双截棍时可以将双截棍的武器伤害与特性加入到天生武器中，占用相应武器位，并导致其无法使用相应的肉搏类武器或其他能力提供的武器模板类效果。<br> 具有【空手道】相关任意能力与异种武器-双截棍专业的单位，持有时获得【Nunchucks连打】的招式。</p><p>Nunchucks连打<br> 动作：自由动作<br> 消耗：1点意志力<br> 目标：见下<br> 持续：一场景<br> 效果：双截棍会随着你的动作被拉开，连接两端的锁链会使双截棍的攻击范围扩大，让你在使用双截棍时（包括将武器伤害与特性加入天生武器后），可以对触及距离内的所有敌对单位进行攻击。<br> 【魔族Slayer提升至B级或以上后，双截棍表面会浮现“魔”“杀”的字迹。】</p><p>二十贯寿司<br> 价格：D+500<br> 分类：奇物<br> 描述：五车首屈一指的寿司板前师傅捏制的特级套餐，包含金枪鱼大腹在内的寿司套组。<br> 寿司富含营养。是能治愈任何伤势的万能食物，古事记中也是这么记载的！当然，不可能发生吃了寿司就能让伤口愈合的神奇现象，但能感觉到吃了寿司后，对魔粒子的循环会变好。<br> 效果：只要在短休息中使用这一奇物，你的对魔粒子能量，就可以在接下来的八小时内，每个小时进行一次能量池关键属性检定，恢复成功数两倍的能量，这会计入每日的恢复上限；你在使用茶道Meditation时，针对疲乏的异常点治疗提升1点，医疗池扩大8点。<br> 这一奇物会每天在盒子里生产二十贯寿司，只要你食用了其中至少一半，在当天内就无需饮食，这些寿司必须吃完才会再次日继续生产。</p><p>Energydrink（能量饮料）<br> 价格：D+500<br> 分类：奇物<br> 描述：上等的健康drink（饮品），虽然是合法物品，但这是通过摄取过量的Caffeine（咖啡因）让大脑暂时陷入兴奋状态的dangernon-alcoholiccocktail危险无酒精鸡尾酒，有很强的提神效果，但因为混合了汉方（中药）和Energydrink（能量饮料），味道实际难以形容。另外，这个饮料的原名叫做马力drink（马力饮料）。<br> 效果：<br> 这一酒杯每天可以无限的产生Energydrink（能量饮料），饮用者在当日内免疫疲乏不良点数带来的减值与严重后果，并且无需睡眠，还会在心智相关检定上获得1DP增强加值，但每日只有第一个饮用者可以享受这些好处，否则就只是单纯难喝的无酒精鸡尾酒。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',55)])])}const C=e(t,[["render",l]]);export{h as __pageData,C as default};
